#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with uint8_t type and specified element count
    hexi::block_allocator<uint8_t, element_count> allocator;

    // Demonstrate allocation: when allocate() is called, it internally calls pop()
    // to remove a block from the free list and returns it
    uint8_t* allocated_block = allocator.allocate();
    // At this point, the free list has been reduced by one block due to pop()

    // Demonstrate deallocation: when deallocate() is called, it internally calls push()
    // to add the block back to the head of the free list
    allocator.deallocate(allocated_block);
    // The block is now pushed back to the free list via push()

    // Additional demonstration showing multiple allocations/deallocations
    uint8_t* block1 = allocator.allocate();
    uint8_t* block2 = allocator.allocate();

    // Free list now has element_count - 2 blocks due to two pop() calls

    allocator.deallocate(block2);
    allocator.deallocate(block1);

    // Both blocks are pushed back to the free list via push(), restoring the original state
}
```

