void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current position by seeking to absolute 0
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write header value (4 bytes)
    uint32_t header_bytes = header_value;
    buffer.write(&header_bytes, sizeof(header_bytes));

    // Write dummy body data (100 bytes)
    std::vector<std::byte> dummy_data(100, std::byte{0});
    buffer.write(dummy_data.data(), dummy_data.size());

    // Return to header position
    buffer.write_seek(hexi::buffer_seek::sk_absolute, 0);

    // Write header value again
    buffer.write(&header_bytes, sizeof(header_bytes));
}

